// ===== 1. SAFE INPUT =====
const lastPulse = input.rows?.[0]?.last_pulse;

// if no data → consider system DOWN
if (!lastPulse) {
  return {
    status: "DOWN",
    expired: true,
    message: "❌ No pulse data found (G1 may be down)",
    alert: "RED"
  };
}

// ===== 2. TIME CALCULATION =====
const now = Math.floor(Date.now() / 1000); // seconds

// handle both seconds & milliseconds automatically
const normalizedLastPulse =
  lastPulse > 1e12 ? Math.floor(lastPulse / 1000) : lastPulse;

const diff = now - normalizedLastPulse;

// ===== 3. WATCHDOG LOGIC =====
const THRESHOLD = 15 * 60; // 15 minutes
const isExpired = diff >= THRESHOLD;

// ===== 4. FORMAT FUNCTIONS =====
const formatDate = (ts) =>
  new Date(ts * 1000).toISOString().replace('T', ' ').slice(0, 19);

const hours = Math.floor(diff / 3600);
const minutes = Math.floor((diff % 3600) / 60);

// ===== 5. STATUS =====
const status = isExpired ? "DOWN" : "ACTIVE";
const alertLevel = isExpired ? "RED" : "NONE";

// ===== 6. EMAIL CONTENT =====
const emailContent = `
<!DOCTYPE html>
<html>
  <body style="font-family: Arial, sans-serif; background-color:#f4f4f4; padding:20px;">
    <div style="max-width:600px; margin:auto; background:white; padding:20px; border-radius:10px; box-shadow:0 0 10px rgba(0,0,0,0.1);">

      <h2 style="color:#333;">⏱️ Pulse Status</h2>

      <p>Hello,</p>
      <p>Here is the current pulse status of <b>G1 Gateway</b>:</p>

      <table style="width:100%; border-collapse: collapse; margin-top:15px;">
        <tr>
          <td style="padding:8px; font-weight:bold;">Last Pulse Time:</td>
          <td style="padding:8px;">${formatDate(normalizedLastPulse)}</td>
        </tr>
        <tr>
          <td style="padding:8px; font-weight:bold;">Current Time:</td>
          <td style="padding:8px;">${formatDate(now)}</td>
        </tr>
        <tr>
          <td style="padding:8px; font-weight:bold;">Time Since Last Pulse:</td>
          <td style="padding:8px;">${hours}h ${minutes}min</td>
        </tr>
        <tr>
          <td style="padding:8px; font-weight:bold;">Status:</td>
          <td style="padding:8px; color:${isExpired ? 'red' : 'green'}; font-weight:bold;">
            ${isExpired ? '❌ DOWN (no activity > 15 minutes)' : '✅ ACTIVE'}
          </td>
        </tr>
      </table>

      ${
        isExpired
          ? `<p style="color:red; margin-top:20px;">
               🚨 Immediate action required: Possible failure in G1 Gateway.
             </p>`
          : ''
      }

      <p style="margin-top:20px;">Best regards,<br/>Sentinel Tower (G5)</p>

    </div>
  </body>
</html>
`;

// ===== 7. Slack CONTENT =====
const slackMessage = `
🚨 *ALERTE CRITIQUE – G1 Gateway DOWN*

• Status: ❌ DOWN  
• Last Pulse: ${formatDate(normalizedLastPulse)}  
• Delay: ${hours}h ${minutes}min  

⚠️ No activity detected for more than 15 minutes.

👉 Action required: Check G1 Gateway immediately.

— Sentinel Tower (G5)
`;

// ===== 8. FINAL OUTPUT =====
return {
  status,
  alert: alertLevel,
  expired: isExpired,
  lastPulseFormatted: formatDate(normalizedLastPulse),
  nowFormatted: formatDate(now),
  diffReadable: `${hours}h ${minutes}min`,
  emailContent,
  slackMessage
};

